async function handleCollegeStats(url, headers) {
  const espnId = url.searchParams.get('espnId');
  const name = url.searchParams.get('name');
  let athleteId = espnId;
  if (!athleteId && name) {
    try {
      const res = await fetch(`https://site.api.espn.com/apis/common/v3/sports/football/college-football/athletes?search=${encodeURIComponent(name)}&limit=5`);
      const d = await res.json();
      if ((d.athletes||[]).length) athleteId = d.athletes[0].id;
    } catch(e) {}
  }
  if (!athleteId) return new Response(JSON.stringify({error:'not found'}), {status:404,headers});
  try {
    const res = await fetch(`https://sports.core.api.espn.com/v2/sports/football/leagues/college-football/athletes/${athleteId}/statistics/0?season=2025`);
    return new Response(await res.text(), {headers});
  } catch(e) {
    return new Response(JSON.stringify({error:'stats failed'}), {status:500,headers});
  }
}
